const raw =
  $json.candidates?.[0]?.content?.parts?.[0]?.text ||
  $json.output ||
  $json.text ||
  $json.response ||
  $json.message ||
  JSON.stringify($json);

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch (error) {
  throw new Error("AI output is not valid JSON: " + error.message + "\nRaw output:\n" + cleaned);
}

return [{ json: data }];
